css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0c0c14; color: white; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; }
.brand { font-size: 19px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: rgba(255,255,255,0.5); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #38bdf8; }
.cart-icon { font-size: 15px; font-weight: 700; cursor: pointer; }
.hero { padding: 60px; background: linear-gradient(135deg, rgba(56,189,248,0.08), transparent); }
.hero-text { max-width: 580px; }
.badge { display: inline-block; color: #38bdf8; font-size: 12px; font-weight: 800; letter-spacing: 0.18em; margin-bottom: 22px; }
.hero h1 { font-size: 46px; font-weight: 800; line-height: 1.3; margin-bottom: 18px; }
.hero h1 span { color: #38bdf8; }
.hero p { color: rgba(255,255,255,0.5); font-size: 15px; line-height: 1.8; }
.products { padding: 0 60px 70px; }
.filter-row { display: flex; gap: 10px; margin: 30px 0; flex-wrap: wrap; }
.filter { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: rgba(255,255,255,0.5); padding: 9px 18px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.filter.active { background: rgba(56,189,248,0.15); color: #38bdf8; border-color: rgba(56,189,248,0.3); }
.product-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 20px; }
.product-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 18px; cursor: pointer; transition: 0.15s; }
.product-card:hover { border-color: rgba(56,189,248,0.3); }
.product-img { aspect-ratio: 16/10; background: linear-gradient(150deg, #1c2840, #0c0c14); border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 40px; margin-bottom: 14px; }
.type-label { display: block; font-size: 11px; color: #38bdf8; font-weight: 800; text-transform: uppercase; letter-spacing: 0.06em; margin-bottom: 6px; }
.product-card h3 { font-size: 15px; font-weight: 700; margin-bottom: 8px; }
.price-row { display: flex; justify-content: space-between; align-items: center; }
.price { font-weight: 800; font-size: 15px; }
.add-btn { background: rgba(56,189,248,0.15); color: #38bdf8; border: none; padding: 8px 16px; border-radius: 999px; font-size: 12px; font-weight: 700; cursor: pointer; }
.cart-drawer { position: fixed; top: 0; right: -380px; width: 360px; height: 100%; background: #14141e; box-shadow: -10px 0 40px rgba(0,0,0,0.4); z-index: 20; transition: right 0.3s; display: flex; flex-direction: column; }
.cart-drawer.open { right: 0; }
.cart-header { display: flex; justify-content: space-between; align-items: center; padding: 24px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.cart-header h2 { font-size: 18px; font-weight: 800; }
.cart-header button { background: none; border: none; color: white; font-size: 18px; cursor: pointer; }
.cart-items { flex: 1; overflow-y: auto; padding: 16px 24px; display: flex; flex-direction: column; gap: 14px; }
.cart-item { display: flex; gap: 14px; align-items: center; }
.cart-item-img { width: 50px; height: 50px; background: rgba(56,189,248,0.08); border-radius: 10px; display: flex; align-items: center; justify-content: center; font-size: 20px; flex-shrink: 0; }
.cart-item-info { flex: 1; }
.cart-item-info h4 { font-size: 13.5px; font-weight: 700; }
.cart-item-info span { font-size: 12.5px; color: rgba(255,255,255,0.4); }
.remove-btn { background: none; border: none; color: rgba(255,255,255,0.3); font-size: 14px; cursor: pointer; }
.cart-footer { padding: 24px; border-top: 1px solid rgba(255,255,255,0.06); }
.cart-total { display: flex; justify-content: space-between; font-size: 16px; font-weight: 800; margin-bottom: 16px; }
.btn-primary.full { width: 100%; background: #38bdf8; color: #0c0c14; border: none; padding: 15px; border-radius: 12px; font-size: 14px; font-weight: 800; cursor: pointer; }
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.5); display: none; z-index: 19; }
.overlay.show { display: block; }
@media (max-width: 900px) { .navbar, .hero, .products { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 30px; } .cart-drawer { width: 100%; right: -100%; } }

