const products = [
  { id: 1, name: 'SaaS Landing Page Kiti (Figma)', cat: 'template', label: 'Şablon', price: 349, emoji: '🎨' },
  { id: 2, name: 'VSCode Tema Paketi', cat: 'plugin', label: 'Eklenti', price: 0, emoji: '🧩' },
  { id: 3, name: 'React ile Modern UI Kursu', cat: 'course', label: 'Kurs', price: 899, emoji: '🎓' },
  { id: 4, name: 'Dashboard UI Kiti', cat: 'template', label: 'Şablon', price: 449, emoji: '📊' },
  { id: 5, name: 'Figma Otomasyon Eklentisi', cat: 'plugin', label: 'Eklenti', price: 199, emoji: '⚙️' },
  { id: 6, name: 'UX Araştırma Yöntemleri Kursu', cat: 'course', label: 'Kurs', price: 749, emoji: '🎓' },
  { id: 7, name: 'Mobil Uygulama Wireframe Kiti', cat: 'template', label: 'Şablon', price: 299, emoji: '📱' },
  { id: 8, name: 'İkon Seti - 500+ İkon', cat: 'template', label: 'Şablon', price: 149, emoji: '🔷' }
];

let cart = [];

function renderProducts(filter) {
  const grid = document.getElementById('productGrid');
  grid.innerHTML = '';
  products
    .filter(p => filter === 'all' || p.cat === filter)
    .forEach(p => {
      const card = document.createElement('div');
      card.className = 'product-card';
      card.innerHTML = `
        <div class="product-img">${p.emoji}</div>
        <span class="type-label">${p.label}</span>
        <h3>${p.name}</h3>
        <div class="price-row">
          <span class="price">${p.price === 0 ? 'Ücretsiz' : '₺' + p.price}</span>
          <button class="add-btn">Sepete Ekle</button>
        </div>
      `;
      card.addEventListener('click', () => addToCart(p));
      grid.appendChild(card);
    });
}

function filterProducts(btn, filter) {
  document.querySelectorAll('.filter').forEach(f => f.classList.remove('active'));
  btn.classList.add('active');
  renderProducts(filter);
}

function addToCart(product) {
  cart.push(product);
  updateCart();
  toggleCart(true);
}

function removeFromCart(index) {
  cart.splice(index, 1);
  updateCart();
}

function updateCart() {
  document.getElementById('cartCount').textContent = cart.length;
  const itemsContainer = document.getElementById('cartItems');
  itemsContainer.innerHTML = '';
  let total = 0;
  cart.forEach((item, i) => {
    total += item.price;
    const div = document.createElement('div');
    div.className = 'cart-item';
    div.innerHTML = `
      <div class="cart-item-img">${item.emoji}</div>
      <div class="cart-item-info"><h4>${item.name}</h4><span>${item.price === 0 ? 'Ücretsiz' : '₺' + item.price}</span></div>
      <button class="remove-btn" onclick="removeFromCart(${i})">✕</button>
    `;
    itemsContainer.appendChild(div);
  });
  document.getElementById('cartTotal').textContent = `₺${total}`;
}

function toggleCart(forceOpen) {
  const drawer = document.getElementById('cartDrawer');
  const overlay = document.getElementById('overlay');
  const shouldOpen = forceOpen !== undefined ? forceOpen : !drawer.classList.contains('open');
  drawer.classList.toggle('open', shouldOpen);
  overlay.classList.toggle('show', shouldOpen);
}

function checkout() {
  if (cart.length === 0) { alert('Sepetiniz boş.'); return; }
  alert('Satın alma tamamlandı! İndirme bağlantıları e-posta adresinize gönderildi.');
  cart = [];
  updateCart();
  toggleCart(false);
}

renderProducts('all');
